      active ? 'text-ink-950 bg-ink-100' : 'text-ink-800 hover:bg-ink-100'
    }`;

  return (
    <header
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-200 ${
        isScrolled
          ? 'bg-ink-50/95 backdrop-blur-md border-b border-ink-200 py-2.5'
