                  {link.label}
                  <ArrowUpRight size={14} aria-hidden />
                </a>
              ))}
            </div>
          ) : null}

          {project.credlyBadge ? (
            <CredlyBadgeBlock badge={project.credlyBadge} />
          ) : null}
        </div>
      )}
    </section>
  );
}

