/** SEO helpers: per-route titles, meta tags, canonical URLs, and JSON-LD. */
import type { SitePage } from './types';
import { CONTACT_INFO, PUBLICATIONS } from './constants';

export const PORTFOLIO_ORIGIN = 'https://dkritarth.com';
const SITE_NAME = 'Kritarth Dandapat';
const DEFAULT_OG_IMAGE = `${PORTFOLIO_ORIGIN}/data/my-photo.jpg`;

export const PAGE_PATHS: Record<SitePage, string> = {
  home: '/',
  about: '/about/',
  research: '/research/',
  projects: '/projects/',
  education: '/education/',
  news: '/news/',
};

/** Visible page title for screen-reader / document outline (one h1 per view). */
export const PAGE_HEADINGS: Record<SitePage, string> = {
  home: `${CONTACT_INFO.name} — AI researcher and incoming PhD student`,

content.content:
20	  home: `${CONTACT_INFO.name} — AI researcher and incoming PhD student`,
21	  about: 'About Kritarth Dandapat',
22	  research: 'Research',
23	  projects: 'Selected projects',
24	  education: 'Education and experience',
25	  news: 'News and milestones',
26	};
27	
28	const HOME_TITLE = `${CONTACT_INFO.name} · AI Researcher · Incoming PhD Student`;
29	const HOME_DESC = CONTACT_INFO.bio;
30	
31	const SEO: Record<SitePage, { title: string; description: string }> = {
32	  home: {
33	    title: HOME_TITLE,
34	    description: HOME_DESC,
35	  },
36	  about: {
37	    title: `About · ${SITE_NAME}`,
38	    description:
39	      'Background, research interests, honors, certifications, and technical skills. Incoming MSU CSE PhD student (Data Mining Laboratory, Dr. Pang-Ning Tan); undergraduate researcher at University at Buffalo.',
40	  },
41	  research: {
42	    title: `Research · ${SITE_NAME}`,
43	    description:
44	      'Healthcare AI (OralScan, OrthoScan, mRehab), computational materials science (symmetry-aware GNNs, equivariant MLIPs), publications, preprints, and presentations.',
45	  },
46	  projects: {
47	    title: `Projects · ${SITE_NAME}`,
48	    description:
49	      'PaddockPsychRL (F1-informed multi-agent RL), Marine Guardian satellite ship detection, CSRNet crowd counting, and multi-architecture emotion detection benchmarks.',
50	  },
51	  education: {
52	    title: `Education & Experience · ${SITE_NAME}`,
53	    description:
54	      'Accelerated BS in Computer Science at UB; incoming PhD at Michigan State University; CSE 341 teaching assistant, tutoring, and student leadership.',
55	  },
56	  news: {
57	    title: `News · ${SITE_NAME}`,
58	    description:
59	      'Timeline of research milestones, awards, publications, and project launches with links and photos.',
60	  },
61	};
62	
63	export function pageCanonicalUrl(page: SitePage): string {
64	  const path = PAGE_PATHS[page];
65	  return path === '/' ? `${PORTFOLIO_ORIGIN}/` : `${PORTFOLIO_ORIGIN}${path}`;
66	}
67	
68	function buildWebSiteNode() {
69	  return {
70	    '@type': 'WebSite',
71	    '@id': `${PORTFOLIO_ORIGIN}/#website`,
72	    name: `${SITE_NAME} — Academic site`,
73	    url: `${PORTFOLIO_ORIGIN}/`,
74	    description: HOME_DESC,
75	    publisher: { '@id': `${PORTFOLIO_ORIGIN}/#person` },
76	    inLanguage: 'en-US',
77	  };
78	}
79	
80	function buildPersonNode() {
81	  return {
82	    '@type': 'Person',
83	    '@id': `${PORTFOLIO_ORIGIN}/#person`,
84	    name: CONTACT_INFO.name,
85	    url: `${PORTFOLIO_ORIGIN}/`,
86	    image: DEFAULT_OG_IMAGE,
87	    email: `mailto:${CONTACT_INFO.email}`,
88	    jobTitle: 'Incoming PhD Student; Undergraduate Researcher',
89	    description: HOME_DESC,
90	    sameAs: [
91	      CONTACT_INFO.github,
92	      CONTACT_INFO.linkedin,
93	      CONTACT_INFO.website,
94	      CONTACT_INFO.inferenceFoundry.url,
95	      'https://www.instagram.com/kritarth_dandapat/',
96	      'https://x.com/Kritarth25',
97	    ],
98	    worksFor: {
99	      '@type': 'CollegeOrUniversity',
100	      name: 'University at Buffalo, SUNY',
101	    },
102	    alumniOf: {
103	      '@type': 'CollegeOrUniversity',
104	      name: 'University at Buffalo, SUNY',
105	    },
106	    affiliation: {
107	      '@type': 'CollegeOrUniversity',
108	      name: 'Michigan State University',
109	    },
110	    knowsAbout: [
111	      'Spatiotemporal machine learning',
112	      'Deep learning-based weather forecasting',
113	      'AI adversarial robustness',
114	      'Computer vision',
115	      'Healthcare AI',
116	      'Materials machine learning',
117	      'Graph neural networks',
118	    ],
119	  };
120	}
121	
122	function buildProfilePageNode(page: SitePage) {
123	  return {
124	    '@type': 'ProfilePage',
125	    '@id': `${pageCanonicalUrl(page)}#webpage`,
126	    url: pageCanonicalUrl(page),
127	    name: SEO[page].title,
128	    description: SEO[page].description,
129	    isPartOf: { '@id': `${PORTFOLIO_ORIGIN}/#website` },
130	    about: { '@id': `${PORTFOLIO_ORIGIN}/#person` },
131	    inLanguage: 'en-US',
132	  };
133	}
134	
135	function buildBreadcrumbNode(page: SitePage) {
136	  const items = [
137	    { '@type': 'ListItem', position: 1, name: 'Home', item: `${PORTFOLIO_ORIGIN}/` },
138	  ];
139	  if (page !== 'home') {
140	    items.push({
141	      '@type': 'ListItem',
142	      position: 2,
143	      name: PAGE_HEADINGS[page],
144	      item: pageCanonicalUrl(page),
145	    });
146	  }
147	  return {
148	    '@type': 'BreadcrumbList',
149	    '@id': `${pageCanonicalUrl(page)}#breadcrumb`,
150	    itemListElement: items,
151	  };
152	}
153	
154	function buildPublicationNodes() {
155	  return PUBLICATIONS.filter((p) => p.link).map((pub, index) => ({
156	    '@type': 'ScholarlyArticle',
157	    '@id': `${PORTFOLIO_ORIGIN}/#publication-${index}`,
158	    headline: pub.title,
159	    author: pub.authors,
160	    datePublished: pub.year,
161	    url: pub.link,
162	    isPartOf: { '@id': `${PORTFOLIO_ORIGIN}/#person` },
163	  }));
164	}
165	
166	function buildStructuredData(page: SitePage): object {
167	  const graph = [
168	    buildWebSiteNode(),
169	    buildPersonNode(),
170	    buildProfilePageNode(page),
171	    buildBreadcrumbNode(page),
172	  ];
173	  if (page === 'research') {
174	    graph.push(...buildPublicationNodes());
175	  }
176	  return {
177	    '@context': 'https://schema.org',
178	    '@graph': graph,
179	  };
180	}
181	
182	export function applyPageSeo(page: SitePage): void {
183	  const { title, description } = SEO[page];
184	  const canonical = pageCanonicalUrl(page);
185	
186	  document.title = title;
187	
188	  ensureMetaName('description').setAttribute('content', description);
189	  ensureMetaName('author').setAttribute('content', CONTACT_INFO.name);
190	  ensureMetaName('robots').setAttribute('content', 'index, follow, max-image-preview:large');
191	
192	  ensureLinkRel('canonical').setAttribute('href', canonical);
193	
194	  ensureMetaProperty('og:type').setAttribute('content', 'profile');
195	  ensureMetaProperty('og:site_name').setAttribute('content', SITE_NAME);
196	  ensureMetaProperty('og:title').setAttribute('content', title);
197	  ensureMetaProperty('og:description').setAttribute('content', description);
198	  ensureMetaProperty('og:url').setAttribute('content', canonical);
199	  ensureMetaProperty('og:locale').setAttribute('content', 'en_US');
200	  ensureMetaProperty('og:image').setAttribute('content', DEFAULT_OG_IMAGE);
201	  ensureMetaProperty('og:image:alt').setAttribute(
202	    'content',
203	    `${CONTACT_INFO.name}, portrait`,
204	  );
205	
206	  ensureMetaName('twitter:card').setAttribute('content', 'summary_large_image');
207	  ensureMetaName('twitter:title').setAttribute('content', title);
208	  ensureMetaName('twitter:description').setAttribute('content', description);
209	  ensureMetaName('twitter:image').setAttribute('content', DEFAULT_OG_IMAGE);
210	  ensureMetaName('twitter:image:alt').setAttribute(
211	    'content',
212	    `${CONTACT_INFO.name}, portrait`,
213	  );
214	
215	  updateJsonLd(buildStructuredData(page));
216	}
217	
218	function updateJsonLd(data: object): void {
219	  const id = 'site-structured-data';
220	  let el = document.getElementById(id) as HTMLScriptElement | null;
221	  if (!el) {
222	    el = document.createElement('script');
223	    el.id = id;
224	    el.type = 'application/ld+json';
225	    document.head.appendChild(el);
226	  }
227	  el.textContent = JSON.stringify(data);
228	}
229	
230	function ensureMetaName(name: string): HTMLMetaElement {
231	  let el = document.querySelector(`meta[name="${name}"]`) as HTMLMetaElement | null;
232	  if (!el) {
233	    el = document.createElement('meta');
234	    el.setAttribute('name', name);
235	    document.head.appendChild(el);
236	  }
237	  return el;
238	}
239	
240	function ensureMetaProperty(property: string): HTMLMetaElement {
241	  let el = document.querySelector(`meta[property="${property}"]`) as HTMLMetaElement | null;
242	  if (!el) {
243	    el = document.createElement('meta');
244	    el.setAttribute('property', property);
245	    document.head.appendChild(el);
246	  }
247	  return el;
248	}
249	
250	function ensureLinkRel(rel: string): HTMLLinkElement {
251	  let el = document.querySelector(`link[rel="${rel}"]`) as HTMLLinkElement | null;
252	  if (!el) {
253	    el = document.createElement('link');
254	    el.setAttribute('rel', rel);
255	    document.head.appendChild(el);
256	  }
257	  return el;
258	}
259

