import React, { useState } from 'react';
import { Section } from './Section';
import { RESEARCH_PLACEMENTS, computeDuration } from '../constants';
import type { ResearchSubproject } from '../types';
import { ContentImageGrid } from './ContentImageGrid';
import { CredlyBadgeBlock } from './CredlyBadgeBlock';
import { ArrowUpRight, ChevronDown, ChevronUp } from 'lucide-react';

const BOLD_TERMS = [
  'OralScan',
  'OrthoScan',
  'YOLOv8',
  'YOLO',
  'GNNs',
  'ALIGNN',
  'mRehab',
  'AWS',
  'Kalman',
  'Weights & Biases',
  'MACE',
  'UMA',
  'MLIPs',
  'E(3)-equivariant',
  'eSEN',
  'Mixture-of-Linear-Experts',
  'PerovskiteOrderingGCNNs',
  'Inference Foundry',
];

function formatBoldTerms(s: string): React.ReactNode[] {
  if (!s) return [];
  const escaped = BOLD_TERMS.map((t) => t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|');
  const re = new RegExp(`(${escaped})`, 'g');
  return s.split(re).map((part, i) =>
    BOLD_TERMS.includes(part) ? (
      <strong key={i} className="text-ink-900 font-semibold">
        {part}
      </strong>
    ) : (
      <span key={i}>{part}</span>
    ),
  );
}

function formatRichLine(text: string): React.ReactNode {
  const nodes: React.ReactNode[] = [];
  let last = 0;
  let linkIdx = 0;
  const re = /(https?:\/\/[^\s)]+)/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(text)) !== null) {
    const before = text.slice(last, m.index);
    nodes.push(...formatBoldTerms(before));
    const href = m[1];
    linkIdx += 1;
    nodes.push(
      <a
        key={`link-${linkIdx}-${m.index}`}
        href={href}
        className="text-ink-900 underline underline-offset-2 hover:no-underline break-all"
        target="_blank"
        rel="noopener noreferrer"
      >
        {href}
      </a>,
    );
    last = m.index + m[0].length;
  }
  nodes.push(...formatBoldTerms(text.slice(last)));
  return <>{nodes}</>;
}

function ResearchProjectCard({ project }: { project: ResearchSubproject }) {
  const [isOpen, setIsOpen] = useState(false);
  const dur = computeDuration(project.period);

  return (
    <section
      id={project.id}
      className="scroll-mt-28 rounded-sm border border-ink-200 bg-white shadow-sm overflow-hidden"
    >
      {/* Always-visible header — click to expand/collapse */}
      <button
        type="button"
        onClick={() => setIsOpen((v) => !v)}
        className="w-full text-left px-5 py-4 md:px-7 md:py-5 flex flex-col gap-3 hover:bg-ink-50 transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-[-2px] focus-visible:outline-ink-900"
        aria-expanded={isOpen}
      >
        <div className="flex items-start justify-between gap-3">
          <h4 className="font-serif text-xl font-semibold leading-snug text-ink-900">{project.name}</h4>
          <span className="mt-0.5 shrink-0 text-ink-500">
            {isOpen ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
          </span>
